#include <stdio.h>
#include <math.h>
#define MAX 100005
int sieve[MAX];
void sieve_of_eratosthenes() {
    for (int i = 2; i * i < MAX; i++) {
        if (sieve[i] == 0) {
            for (int j = i * i; j < MAX; j += i) {
                sieve[j] = 1;
            }
        }
    }
}
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
int count_prime_factors(int n) {
    int count = 0;
    for (int i = 2; i * i <= n; i++) {
        if (sieve[i] == 0 && n % i == 0) {
            count++;
            while (n % i == 0) n /= i;
        }
    }
    if (n > 1) count++;
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    sieve_of_eratosthenes();
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int max_useful = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int subsequence[N];
            int length = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    subsequence[length++] = A[i];
                }
            }
            if (length == 0) continue;
            int gcd_value = subsequence[0];
            for (int i = 1; i < length; i++) {
                gcd_value = gcd(gcd_value, subsequence[i]);
            }
            int useful = count_prime_factors(gcd_value) * length;
            max_useful = max_useful > useful ? max_useful : useful;
        }
        printf("%d\n", max_useful);
    }
    return 0;
}

